Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it spins up an in-memory test server with no real ports or network:

```csharp
// 1. Add these packages to your test project:
//    Microsoft.AspNetCore.Mvc.Testing
//    Microsoft.NET.Test.Sdk + xunit (or your preferred runner)

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize session first (Streamable HTTP may require it)
        var init = await InitializeSession();
        var sessionId = init.Headers.GetValues("Mcp-Session-Id").First();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };
        var msg = new HttpRequestMessage(HttpMethod.Post, "/mcp");
        msg.Content = JsonContent.Create(request);
        msg.Headers.Add("Mcp-Session-Id", sessionId);

        var response = await _client.SendAsync(msg);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

**Key points:**

- **`WebApplicationFactory<Program>`** boots your real DI container, middleware, and routing in-process — full fidelity, no mocks.
- **`CreateClient()`** gives you an `HttpClient` wired to the in-memory server.
- If your server uses **Streamable HTTP**, track the `Mcp-Session-Id` header across requests.
- If it uses **SSE**, read the streaming response with `HttpCompletionOption.ResponseHeadersRead` and parse `text/event-stream` lines.
- Override services for testing via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))`.

This is the same pattern used for any ASP.NET Core integration test — MCP is just JSON-RPC over HTTP, so no special test infrastructure is needed.
